from datetime import datetime, timedelta, timezone
from functools import wraps
import os
import jwt
from flask import Flask, request, jsonify, g

app = Flask(__name__)
app.config["SECRET_KEY"] = os.environ.get("JWT_SECRET_KEY", "change-this-secret-key")
app.config["JWT_ALGORITHM"] = "HS256"
app.config["JWT_EXPIRES_MINUTES"] = int(os.environ.get("JWT_EXPIRES_MINUTES", "60"))

# Simple in-memory user store for demo purposes
USERS = {
    "admin": "password123",
    "user": "user123",
}


def create_token(username):
    now = datetime.now(timezone.utc)
    payload = {
        "sub": username,
        "iat": now,
        "exp": now + timedelta(minutes=app.config["JWT_EXPIRES_MINUTES"]),
    }
    return jwt.encode(payload, app.config["SECRET_KEY"], algorithm=app.config["JWT_ALGORITHM"])


def decode_token(token):
    return jwt.decode(
        token,
        app.config["SECRET_KEY"],
        algorithms=[app.config["JWT_ALGORITHM"]],
    )


def jwt_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get("Authorization", "")
        if not auth_header.startswith("Bearer "):
            return jsonify({"message": "Missing or invalid Authorization header"}), 401

        token = auth_header.split(" ", 1)[1].strip()
        if not token:
            return jsonify({"message": "Missing token"}), 401

        try:
            payload = decode_token(token)
            g.current_user = payload.get("sub")
        except jwt.ExpiredSignatureError:
            return jsonify({"message": "Token has expired"}), 401
        except jwt.InvalidTokenError:
            return jsonify({"message": "Invalid token"}), 401

        return f(*args, **kwargs)

    return decorated


@app.route("/login", methods=["POST"])
def login():
    data = request.get_json(silent=True) or {}
    username = data.get("username")
    password = data.get("password")

    if not username or not password:
        return jsonify({"message": "Username and password are required"}), 400

    if USERS.get(username) != password:
        return jsonify({"message": "Invalid credentials"}), 401

    token = create_token(username)
    return jsonify({"access_token": token})


@app.route("/profile", methods=["GET"])
@jwt_required
def profile():
    return jsonify({
        "message": "Authenticated request successful",
        "user": g.current_user,
    })


@app.route("/public", methods=["GET"])
def public():
    return jsonify({"message": "This is a public endpoint"})


if __name__ == "__main__":
    app.run(debug=True)